package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreSurroundingSpaces() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withIgnoreSurroundingSpaces();

        // Then
        assertTrue(result.getIgnoreSurroundingSpaces());
    }

    @Test
    public void testWithIgnoreSurroundingSpacesFalse() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces();

        // When
        CSVFormat result = csvFormat.withIgnoreSurroundingSpaces(false);

        // Then
        assertFalse(result.getIgnoreSurroundingSpaces());
    }

    @Test
    public void testWithIgnoreSurroundingSpacesTwice() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withIgnoreSurroundingSpaces().withIgnoreSurroundingSpaces();

        // Then
        assertTrue(result.getIgnoreSurroundingSpaces());
    }
}
